const output = $input.first().json.output || '';
return [{
  json: {
    response: output
  }
}];

const data = $input.first().json.output;
const monthlyIncome = Number($('Edit Fields1').first().json['Ingreso-mensual']);
const userId = $('Edit Fields1').first().json.userId;

const categories = data.categories.map(cat => ({
  userId: userId,
  name: cat.name,
  emoji: cat.emoji,
  budget: Math.round(cat.budget * monthlyIncome),
  alert_threshold: Math.round(cat.alert_threshold * monthlyIncome),
}));

return [{ json: { categories } }];

